CREATE TABLE IF NOT EXISTS material_source_ledger (
  source_id TEXT PRIMARY KEY,
  book_id TEXT NOT NULL UNIQUE,
  catalog_source TEXT NOT NULL,
  book_title TEXT NOT NULL,
  edition TEXT NOT NULL,
  rights_status TEXT NOT NULL CHECK (rights_status IN ('approved', 'pending', 'unknown', 'blocked')),
  review_status TEXT NOT NULL CHECK (review_status IN ('approved', 'needs_review', 'blocked')),
  source_file TEXT NOT NULL,
  extracted_at TEXT NOT NULL,
  transform_log TEXT NOT NULL,
  content_qa_report TEXT NOT NULL,
  qa_word_count INTEGER NOT NULL DEFAULT 0,
  qa_required_blank_rows INTEGER NOT NULL DEFAULT 0,
  qa_rows_with_sentinel INTEGER NOT NULL DEFAULT 0,
  qa_sentinel_value_count INTEGER NOT NULL DEFAULT 0,
  qa_duplicate_headword_count INTEGER NOT NULL DEFAULT 0,
  qa_source_coverage_rate REAL NOT NULL DEFAULT 0,
  qa_example_pair_coverage_rate REAL NOT NULL DEFAULT 0,
  notes TEXT NOT NULL DEFAULT '',
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL,
  FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS idx_material_source_ledger_status
  ON material_source_ledger(review_status, rights_status, catalog_source);

