INSERT INTO material_source_ledger (
  source_id,
  book_id,
  catalog_source,
  book_title,
  edition,
  rights_status,
  review_status,
  source_file,
  extracted_at,
  transform_log,
  content_qa_report,
  qa_word_count,
  qa_required_blank_rows,
  qa_rows_with_sentinel,
  qa_sentinel_value_count,
  qa_duplicate_headword_count,
  qa_source_coverage_rate,
  qa_example_pair_coverage_rate,
  notes,
  created_at,
  updated_at
)
SELECT
  source_rows.source_id,
  source_rows.book_id,
  source_rows.catalog_source,
  source_rows.book_title,
  source_rows.edition,
  source_rows.rights_status,
  source_rows.review_status,
  source_rows.source_file,
  source_rows.extracted_at,
  source_rows.transform_log,
  source_rows.content_qa_report,
  source_rows.qa_word_count,
  source_rows.qa_required_blank_rows,
  source_rows.qa_rows_with_sentinel,
  source_rows.qa_sentinel_value_count,
  source_rows.qa_duplicate_headword_count,
  source_rows.qa_source_coverage_rate,
  source_rows.qa_example_pair_coverage_rate,
  source_rows.notes,
  source_rows.created_at,
  source_rows.updated_at
FROM source_rows
INNER JOIN books b ON b.id = source_rows.book_id
ON CONFLICT(book_id) DO UPDATE SET
  catalog_source = excluded.catalog_source,
  book_title = excluded.book_title,
  edition = excluded.edition,
  rights_status = excluded.rights_status,
  review_status = excluded.review_status,
  source_file = excluded.source_file,
  extracted_at = excluded.extracted_at,
  transform_log = excluded.transform_log,
  content_qa_report = excluded.content_qa_report,
  qa_word_count = excluded.qa_word_count,
  qa_required_blank_rows = excluded.qa_required_blank_rows,
  qa_rows_with_sentinel = excluded.qa_rows_with_sentinel,
  qa_sentinel_value_count = excluded.qa_sentinel_value_count,
  qa_duplicate_headword_count = excluded.qa_duplicate_headword_count,
  qa_source_coverage_rate = excluded.qa_source_coverage_rate,
  qa_example_pair_coverage_rate = excluded.qa_example_pair_coverage_rate,
  notes = excluded.notes,
  updated_at = excluded.updated_at;
